def listar_pedidos_con_usuario(db, pedidos):
    resultado = []
    for pedido in pedidos:
        usuario = db.execute("SELECT * FROM usuarios WHERE id = ?", pedido.usuario_id).fetchone()
        resultado.append({**pedido, "usuario": usuario})
    return resultado

